from dependency_plan import Dependency, dependency_plan
from service_container import Container


def test_plan_describes_required_keyword_only_dependency():
    def publisher(*, audit_log):
        return audit_log

    assert dependency_plan(publisher) == (
        Dependency("audit_log", "keyword"),
    )


def test_container_binds_keyword_only_dependency_by_name():
    container = Container()
    container.register("audit_log", lambda: "audit-ready")

    def publisher(*, audit_log):
        return f"publisher:{audit_log}"

    container.register("publisher", publisher)

    assert container.resolve("publisher") == "publisher:audit-ready"
